	if string[1] == 'L'
		y = x - (num % 100)
		if x > 0 && y <= 0
			s0 += 1
		end
	elseif string[1] == 'R'
		y = x + (num % 100)
		if x < 100 && y >= 100
			s0 += 1
		end
	end
	s0 += div(num, 100)
	y = mod(y, 100 )
	#println("y -> $y, s0 -> $s0")

	return y, s0, string
end


