inputsize = [139, 139]
input = reshape(input, inputsize...)

refinedi::Matrix{Integer} = reshape(zeros(Integer, size(input)...), inputsize...)

for i in 1:length(input)
	#print(input[i])
	if input[i] == '@'
		global refinedi[i] = 1
		end
	if input[i] == '.'
		global refinedi[i] = 0
	end
end

#refinedi = vcat(zeros(Integer, inputsize[1])'   ,refinedi, zeros(Integer, inputsize[1])')
#refinedi = hcat(zeros(Integer, inputsize[2] + 2),refinedi, zeros(Integer, inputsize[2] + 2))

#println(refinedi, typeof(refinedi))

function convolution(A::Matrix, B::Matrix; larger=true)::Matrix{Integer}
	"Here, A must be the larger matrix, B 3x3 matrix. `larger` gives the padding"
	sizeA = size(A)
	res = zeros(sizeA[1] + 2, sizeA[2] + 2)
	for i = 1 : sizeA[1]
		for j = 1 : sizeA[2]
			value::Matrix = A[i, j]::Number * B
			for q = -1:1
				for w = -1:1
					res[(i+q+1),(w+j+1)] += value[(q + 2), (w + 2)]
				end
			end
		end
	end
	if larger return res
	else return res[begin+1:end-1, begin+1:end-1];end
end

showmatrix(M::Matrix) = [println(M'[i, :]) for i in 1:size(M)[2]]


@time begin
	neighbours = ones(Integer, 3, 3)
	neighbours[2, 2] = 0
	major_counter = 0
	global counter = 0

	@time answermatrix = convolution(refinedi, neighbours, larger=false)

	#showmatrix(answermatrix)
	#println()
	#showmatrix(refinedi)
	#println(input)
	for i in 1:length(answermatrix)
		if answermatrix[i] < 4 && refinedi[i] == 1
			global counter += 1
			global refinedi[i] =0
		end
	end
	printstyled("Part 1 answer $counter\n", color=:magenta, bold=true)
	#showmatrix(refinedi)

	global major_counter += counter


	# Part two is here yay
	while counter > 0
		global counter = 0
		global answermatrix = convolution(refinedi, neighbours, larger=false)
		for i in 1:length(answermatrix)
			if answermatrix[i] < 4 && refinedi[i] == 1
				global counter += 1
				refinedi[i] = 0
			end
		end
		global major_counter += counter
	end

	printstyled("Part 2 answer $major_counter", color=:light_magenta, bold=true)

	#println(length(findall(cutoff, enumerate(answermatrix))))
end

